using AIStudyHub.Business.Interfaces.AI.Search;
using AIStudyHub.Business.AI.Search; using AIStudyHub.Business.Interfaces.AI.Guardrails; using Microsoft.Extensions.Logging;  namespace AIStudyHub.Business.AI.Guardrails;  public record GroundingResult(     bool IsGrounded,     double Score,     List<string> UngroundedClaims );  public class GroundingVerifier : IGroundingVerifier {     private readonly ILogger<GroundingVerifier> _logger;      public GroundingVerifier(ILogger<GroundingVerifier> logger)     {         _logger = logger;     }      public Task<GroundingResult> VerifyAsync(string answer, IEnumerable<SearchResult> sources)     {         var sourceTexts = sources.Select(s => s.Content.ToLowerInvariant()).ToList();         var answerLower = answer.ToLowerInvariant();         var ungrounded = new List<string>();          var sourceWords = sourceTexts             .SelectMany(t => t.Split(' ', StringSplitOptions.RemoveEmptyEntries))             .Where(w => w.Length > 4)             .Distinct()             .ToHashSet();          var answerWords = answerLower.Split(' ', StringSplitOptions.RemoveEmptyEntries);         var groundedCount = answerWords.Count(w => sourceWords.Contains(w));         var coverage = answerWords.Length > 0 ? (double)groundedCount / answerWords.Length : 0;          _logger.LogInformation("Grounding verification: {Coverage:P2} coverage", coverage);          return Task.FromResult(new GroundingResult(             IsGrounded: coverage > 0.3,             Score: coverage,             UngroundedClaims: ungrounded         ));     } }
